const currentSongName = computed(() => songs.value[currentIndex.value]?.name || '')

function setupVisualizer() {
    if (!audio) return
    if (!audioContext) {
        audioContext = new (window.AudioContext || window.webkitAudioContext)()
    }

    if (!source) {
        try {
            source = audioContext.createMediaElementSource(audio)
        } catch (e) {
            console.warn('No se pudo crear MediaElementSource (quizá ya existe):', e)
        }
    }

    if (!analyser) {
        analyser = audioContext.createAnalyser()
        analyser.fftSize = 512
        const bufferLength = analyser.frequencyBinCount
        dataArray = new Uint8Array(bufferLength)
    }

    // conectar si no conectado
    try {
        if (source && analyser) {
            source.connect(analyser)
            analyser.connect(audioContext.destination)
        }
    } catch (e) {
        console.warn('Error al conectar audio nodes:', e)
    }

    drawVisualizer()

    // En iOS el context inicia suspendido; reanuda con el primer touch/click.
    if (audioContext.state === 'suspended') {
        const resume = async () => {
            try {
                await audioContext.resume()
            } catch (err) {
                console.warn('Error resuming audioContext:', err)
            } finally {
                document.removeEventListener('touchstart', resume)
                document.removeEventListener('click', resume)
            }
        }
        document.addEventListener('touchstart', resume, { once: true })
        document.addEventListener('click', resume, { once: true })
    }
}

