function drawVisualizer() {
    const canvas = canvasRef.value
    const ctx = canvas.getContext('2d')
    const width = canvas.width
    const height = canvas.height
    const centerX = width / 2
    const centerY = height / 2

    analyser.fftSize = 512 // Resolución más pequeña capta bandas más anchas (más energía)

    let currentRadius = 40
    const baseRadius = 40
    const maxExpand = 58

    let baseline = 0;
    let currentFactorSmoothed = 0;

    function draw() {
        animationId = requestAnimationFrame(draw)
        analyser.getByteFrequencyData(dataArray)

        // 1. Ampliamos el rango de frecuencias graves para captar más cuerpo del sonido
        let sumLow = 0;
        const lowBins = 100;
        for (let i = 0; i < lowBins; i++) {
            sumLow += dataArray[i];
        }
        const currentLowIntensity = sumLow / lowBins;

        // 2. Línea base altamente responsiva (reacciona rápido al cambio del audio)
        baseline = (baseline * 0.90) + (currentLowIntensity * 0.10);

        // 3. Expansión constante multiplicada brutalmente para que el ambiente lo mueva
        // Multiplicamos por 2.5 la intensidad para que "cualquier cosita" lo haga vibrar
        const ambientExpansion = Math.min(1, (currentLowIntensity * 5) / 255) * (maxExpand * 0.6);

        // B) Expansión por pico (UDU): Threshold ultra bajo para que el mínimo acento dispare el verde
        let beatExpansion = 0;
        const threshold = 5 // Apenas asome una frecuencia, salta

        if (currentLowIntensity > baseline + threshold) {
            let beatIntensity = currentLowIntensity - baseline;
            // Multiplicador agresivo para que llene el canvas
            beatExpansion = Math.min(1, (beatIntensity * 6) / 255) * (maxExpand * 0.6);
        }

        const targetRadius = baseRadius + ambientExpansion + beatExpansion;

        // Mismo rebote suave
        const smoothingFactor = targetRadius > currentRadius ? 0.40 : 0.05;
        currentRadius += (targetRadius - currentRadius) * smoothingFactor;

        ctx.clearRect(0, 0, width, height)

        // 4. Color: Si el radio está al 5% de expandirse por el beat, ya empieza a ser verde
        const rawFactor = Math.min(1, Math.max(0, ((currentRadius - baseRadius) / maxExpand) * 1.5));
        currentFactorSmoothed += (rawFactor - currentFactorSmoothed) * 0.08;

        const r = Math.floor(0 + (50 * currentFactorSmoothed));
        const g = Math.floor(150 + (105 * currentFactorSmoothed));
        const b = Math.floor(255 - (205 * currentFactorSmoothed));

        const gradient = ctx.createRadialGradient(
            centerX, centerY, baseRadius * 0.5,
            centerX, centerY, currentRadius
        )

        gradient.addColorStop(0, `rgba(${r}, ${g}, ${b}, 0.8)`)
        gradient.addColorStop(0.5, `rgba(${r}, ${g}, ${b}, 0.3)`)
        gradient.addColorStop(1, `rgba(${r}, ${g}, ${b}, 0)`)

        ctx.beginPath()
        ctx.fillStyle = gradient
        ctx.arc(centerX, centerY, currentRadius, 0, Math.PI * 2)
        ctx.fill()

        ctx.beginPath()
        ctx.lineWidth = 2
        ctx.strokeStyle = `rgba(${r}, ${g}, ${b}, ${currentFactorSmoothed + 0.2})`
        ctx.arc(centerX, centerY, currentRadius, 0, Math.PI * 2)
        ctx.stroke()
    }
    draw()
}

function shuffleArray(length) {
    const indices = [...Array(length).keys()]
    for (let i = indices.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1))
            ;[indices[i], indices[j]] = [indices[j], indices[i]]
    }
    return indices
}
function CloseMoment() {
    moment.value = false
}


let currentObjectURL = null;

async function loadTrack(index) {
    const song = songs.value[index]
    if (!song) return

    // Revoke old blob to prevent memory leaks
    if (currentObjectURL) {
        URL.revokeObjectURL(currentObjectURL);
        currentObjectURL = null;
    }

    let audioSrc = song.url;

    // Load from cache directly as a Blob URL if offline
    if (isOffline.value && downloadedTracks.value.has(song.id)) {
        try {
            if ('caches' in window) {
                const cache = await caches.open('angerpulse-audio-cache');
                const response = await cache.match(song.url);
                if (response) {
                    const blob = await response.blob();
                    currentObjectURL = URL.createObjectURL(blob);
                    audioSrc = currentObjectURL;
                }
            }
        } catch (e) {
            console.error("Error loading blob from cache:", e);
        }
    }

    audio.src = audioSrc;
    durationSong.value = 0;
    audio.load();
    audio.muted = false;
    audio.volume = 1;
    stopPlaybackTimer();

    // si quieres reproducir inmediatamente SOLO si isPlaying está true
    if (isPlaying.value) {
        // Asegura que el audioContext esté activo antes de play
        if (audioContext && audioContext.state === 'suspended') {
            audioContext.resume().catch(e => console.warn('resume falló', e))
        }
        audio.play().then(() => {
            isPlaying.value = true
            startPlaybackTimer()
        }).catch(err => {
            console.warn('iOS puede haber bloqueado la reproducción:', err)
        })
    } else {
        isPlaying.value = false
    }
}

// function toggleLoop() {
//     isLoop.value = !isLoop.value
// }
function toggleLoop() {
    loopMode.value = (loopMode.value + 1) % 3
    audio.loop = (loopMode.value === 2)
}

async function togglePlay() {
    try {
        if (audioContext && audioContext.state === 'suspended') {
            await audioContext.resume()
        }
    } catch (err) {
        console.warn('No se pudo reanudar audioContext:', err)
    }

    if (audio.paused) {
        try {
            // asegúrate el elemento no esté mute y volumen ok
            audio.muted = false
            audio.volume = 1
            await audio.play()
            isPlaying.value = true
            startPlaybackTimer()
        } catch (err) {
            console.warn('Error al play (iOS puede bloquear):', err)
        }
    } else {
        SetPlay(1)
        audio.pause()
        isPlaying.value = false
        stopPlaybackTimer()
        countPause.value++;
        if (!hasShownMomentThisSession() && (playbackSeconds.value >= 15 | (playbackSeconds.value >= 14 && countPause.value > 1))) {
            moment.value = true;
            playbackSeconds.value = 0;
            hasShownMessage.value = true
            markMomentAsShown()
            showMomentButton.value = false
            countPause.value = 0
        }
    }
}


function startPlaybackTimer() {
    if (playbackInterval) return // Evita múltiples intervalos

    playbackInterval = setInterval(() => {
        playbackSeconds.value++
        durationSong.value++
    }, 1000)
}

function stopPlaybackTimer() {
    clearInterval(playbackInterval)
    playbackInterval = null
}

function nextTrack(isAuto = false) {
    SetPlay(0)
    const auto = isAuto === true

    if (isShuffle.value) {
        if (shuffledIndices.length === 0) {
            if (loopMode.value === 0 && auto) {
                isPlaying.value = false
                stopPlaybackTimer()
                return
            }
            shuffledIndices = shuffleArray(songs.value.length)
        }
        currentIndex.value = shuffledIndices.shift()
    } else {
        if (loopMode.value === 0 && auto && currentIndex.value === songs.value.length - 1) {
            isPlaying.value = false
            stopPlaybackTimer()
            return
        }
        currentIndex.value = (currentIndex.value + 1) % songs.value.length
    }
    isPlaying.value = true
    loadTrack(currentIndex.value)
}

function prevTrack() {
    SetPlay(0)
    if (isShuffle.value) {
        if (shuffledIndices.length === 0) {
            shuffledIndices = shuffleArray(songs.value.length)
        }
        currentIndex.value = shuffledIndices.shift()
    } else {
        currentIndex.value = (currentIndex.value - 1 + songs.value.length) % songs.value.length
    }
    isPlaying.value = true
    loadTrack(currentIndex.value)
}

function toggleShuffle() {
    isShuffle.value = !isShuffle.value

    if (isShuffle.value) {
        shuffledIndices = shuffleArray(songs.value.length)
        // Evita repetir la canción actual
        shuffledIndices = shuffledIndices.filter(i => i !== currentIndex.value)
    } else {
        shuffledIndices = []
    }
}

function seekAudio() {
    audio.currentTime = currentTime.value
}

audio.addEventListener('timeupdate', () => {
    currentTime.value = audio.currentTime
    duration.value = audio.duration || 0
})

