function formatTime(time) {
    const minutes = Math.floor(time / 60)
    const seconds = Math.floor(time % 60).toString().padStart(2, '0')
    return `${minutes}:${seconds}`
}

// const audios = ref([]);
function limpiarNombre(nombre) {
    return nombre.replace(/\.[^.]+(?=\.\w+$)/, '') // quita hash intermedio
}

async function GetAudios() {
    try {
        const sesion = localStorage.getItem("token")
        if (!sesion) {
            isLoading.value = false;
            return;
        }

        let dataAudios = null

        if (isOffline.value) {
            const savedStr = localStorage.getItem('audioteca_offline_list_' + sesion);
            if (savedStr) {
                songs.value = JSON.parse(savedStr);
                await checkDownloadedState();
                songs.value = songs.value.filter(s => downloadedTracks.value.has(s.id));
            } else {
                songs.value = [];
            }
            if (songs.value.length > 0) {
                loadTrack(0);
            }
            isLoading.value = false;
            return;
        }

        const response = await fetch(`${API_BASE_URL}/api/audioteca/GetAudioteca`, {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ username: sesion })
        })

        if (!response.ok) throw new Error("Error en la petición")

        const data = await response.json()

        if (data.data != "") {
            dataAudios = Array.isArray(JSON.parse(data.data)) ? JSON.parse(data.data) : data.data
            if (!Array.isArray(dataAudios)) throw new Error("dataAudios no es un array")

            const arr = dataAudios.map(item => {
                const limpio = limpiarNombre(item.NombreAudio)
                return {
                    id: item.Id_Audioteca,
                    url: `/audios/${limpio}`,
                    nombre: item.Nombre,
                    segundos: item.Segundos
                }
            })

            songs.value = arr.map(item => ({
                id: item.id,
                name: item.nombre,
                url: item.url,
                seg: item.segundos
            }))

            localStorage.setItem('audioteca_offline_list_' + sesion, JSON.stringify(songs.value));
            await checkDownloadedState();

            // Cargar primer track solo después de tener audios
            if (songs.value.length > 0) {
                loadTrack(0)
            }
        }
        else {
            songs.value = [];
            localStorage.setItem('audioteca_offline_list_' + sesion, JSON.stringify(songs.value));
            return;
        }

    } catch (error) {
        console.error("Error al cargar audios:", error)
        try {
            const sesion = localStorage.getItem("token")
            const savedStr = localStorage.getItem('audioteca_offline_list_' + sesion);
            if (savedStr) {
                songs.value = JSON.parse(savedStr);
                await checkDownloadedState();
                songs.value = songs.value.filter(s => downloadedTracks.value.has(s.id));
                if (songs.value.length > 0) loadTrack(0);
            }
        } catch (innerError) {
            console.error(innerError)
        }
    } finally {
        isLoading.value = false;
    }
}

async function initAudioPlayer() {
    await GetAudios() // carga los audios primero
    if (songs.value.length === 0) return

    await nextTick() // Permitir que Vue renderice el canvas antes de buscar su ref
    loadTrack(0)
    setupVisualizer()
}

async function checkDownloadedState() {
    if (!('caches' in window)) return;
    try {
        const cache = await caches.open('angerpulse-audio-cache');
        const downloaded = new Set();
        for (const song of songs.value) {
            const response = await cache.match(song.url);
            if (response) {
                downloaded.add(song.id);
            }
        }
        downloadedTracks.value = downloaded;
    } catch (e) {
        console.error("Error checking cache:", e);
    }
}

async function downloadAudio(song) {
    if (!('caches' in window) || downloadedTracks.value.has(song.id)) return;

    downloadingTracks.value.add(song.id);
    try {
        const cache = await caches.open('angerpulse-audio-cache');
        const response = await fetch(song.url);
        if (response.ok) {
            await cache.put(song.url, response.clone());
            downloadedTracks.value.add(song.id);
        }
    } catch (e) {
        console.error("Error al descargar audio:", e);
    } finally {
        downloadingTracks.value.delete(song.id);
    }
}

function updateOnlineStatus() {
    isOffline.value = !navigator.onLine
    if (!isOffline.value) {
        isLoading.value = true;
        initAudioPlayer();
        syncOfflineActivity();
    }
}

onMounted(() => {
    initAudioPlayer()
    window.addEventListener('online', updateOnlineStatus)
    window.addEventListener('offline', updateOnlineStatus)
    document.addEventListener('visibilitychange', handleVisibilityChange)
    window.addEventListener('beforeunload', handleBeforeUnload)
    showMomentButton.value = !hasShownMomentThisSession()
    // GetAudios()
    // setupVisualizer()
    // loadTrack(currentIndex.value)
})

function handleVisibilityChange() {
    if (document.hidden && isPlaying.value) {
        SetPlay(1)
    }
}

function handleBeforeUnload() {
    if (isPlaying.value) {
        SetPlay(1)
    }
}

onBeforeUnmount(() => {
    if (isPlaying.value) {
        SetPlay(1)
    }
    window.removeEventListener('online', updateOnlineStatus)
    window.removeEventListener('offline', updateOnlineStatus)
    document.removeEventListener('visibilitychange', handleVisibilityChange)
    window.removeEventListener('beforeunload', handleBeforeUnload)
    cancelAnimationFrame(animationId)
    audio.pause()
    audio.src = ''
    if (audioContext) audioContext.close()
})



const editingIndex = ref(null)
const editedName = ref('')

function playSong(index) {
    isPlaying.value = true
    currentIndex.value = index
    loadTrack(index)
    startPlaybackTimer()
    isPlaying.value = true
}

function removeSong(index) {
    const songToDelete = songs.value[index]

    const isCurrent = currentIndex.value === index
    if (isCurrent) {
        audio.pause()
        isPlaying.value = false
        stopPlaybackTimer()
    }

    // if (currentIndex.value === index) {
    //     audio.pause()
    // }
    // Ajustamos currentIndex si es necesario
    if (songs.value.length === 0) {
        // No quedan canciones
        currentIndex.value = 0
        audio.src = ''
        return
    }
    if (currentIndex.value > index) {
        // Si la canción eliminada estaba antes de la actual, decrementamos el índice
        currentIndex.value -= 1
    } else if (currentIndex.value === index) {
        // Si eliminamos la canción actual, cargamos la siguiente disponible
        if (currentIndex.value >= songs.value.length) {
            currentIndex.value = 0
        }
    }

    // Llamamos a la API para eliminar favorito
    DeleteFavorite(songToDelete.id)
    // Si queda alguna canción, la cargamos y reproducimos
    if (songs.value.length > 0) {
        loadTrack(currentIndex.value)
        isPlaying.value = true
        startPlaybackTimer()
    }
    songs.value.splice(index, 1)
    if (currentIndex.value >= songs.value.length) {
        currentIndex.value = 0
    }
    // DeleteFavorite()
    // loadTrack(currentIndex.value)
}

