const listRef = ref(null)

// Drag & touch
const isDragging = ref(false)
const readyIndex = ref(null)
const dragText = ref("")
const fingerOffsetY = ref(0)
const floatY = ref(0)
const containerRect = ref({ top: 0, bottom: 0, left: 0, width: 0 })

let touchTimer = null // temporizador para delay de drag

const floatingStyle = computed(() => ({
    position: "fixed",
    top: `${Math.min(Math.max(floatY.value - fingerOffsetY.value, containerRect.value.top),
        containerRect.value.bottom - 1)}px`,
    left: `${containerRect.value.left}px`,
    width: `${containerRect.value.width}px`,
    zIndex: 9999,
    pointerEvents: "none"
}))

function startTouch(index, e) {
    // Guardamos info para el posible drag
    const t = e.touches[0]
    const el = e.currentTarget
    const itemRect = el.getBoundingClientRect()
    const listBox = listRef.value.getBoundingClientRect()
    containerRect.value = {
        top: listBox.top,
        bottom: listBox.bottom,
        left: listBox.left,
        width: listBox.width
    }

    fingerOffsetY.value = t.clientY - itemRect.top
    floatY.value = t.clientY

    // Iniciamos temporizador de 2s para drag
    touchTimer = setTimeout(() => {
        isDragging.value = true
        currentIndex.value = index
        dragText.value = songs.value[index].name
    }, 500)
}

function onDrag(e) {
    if (!isDragging.value)
        return

    e.preventDefault() // SOLO cuando realmente estás arrastrando

    const t = e.touches[0]
    floatY.value = t.clientY

    const targetIndex = indexFromY(t.clientY)
    if (targetIndex == null || targetIndex === currentIndex.value) return

    const arr = songs.value
    const moved = arr.splice(currentIndex.value, 1)[0]
    arr.splice(targetIndex, 0, moved)
    currentIndex.value = targetIndex
}
// const canvasRefs = ref([])

function endDrag() {
    clearTimeout(touchTimer)
    if (!isDragging.value) return

    // Guardamos el índice del item que se soltó
    const releasedIndex = currentIndex.value

    // Reset de estado drag
    isDragging.value = false
    currentIndex.value = null
    dragText.value = ""
    readyIndex.value = null
    document.querySelectorAll('.lisongs').forEach(item => item.classList.remove('is-ready'))

    isPlaying.value = true
    currentIndex.value = releasedIndex
    // loadTrack(index)
    startPlaybackTimer()
    isPlaying.value = true
}


function indexFromY(y) {
    const container = listRef.value
    if (!container) return null
    const children = Array.from(container.querySelectorAll(".lisongs"))
    if (!children.length) return null
    for (let i = 0; i < children.length; i++) {
        const r = children[i].getBoundingClientRect()
        const mid = r.top + r.height / 2
        if (y < mid) return i
    }
    return children.length - 1
}

async function SetMoment() {
    await SetPlay(1);
    try {
        const sesion = localStorage.getItem("token")
        if (!sesion) return

        const payload = {
            idMomento: Number(selectedMoment.value),
            idUser: sesion,
            idAudio: idPlay.value
        };

        if (isOffline.value) {
            const key = `offline_moments_${sesion}`;
            let queue = [];
            try {
                queue = JSON.parse(localStorage.getItem(key) || '[]');
            } catch (e) { console.error(e); }
            queue.push(payload);
            localStorage.setItem(key, JSON.stringify(queue));
            moment.value = false;
            return;
        }

        const response = await fetch(`${API_BASE_URL}/api/config/SetMoment`, {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify(payload),
            keepalive: true
        })
        moment.value = false
        if (!response.ok) throw new Error("Error en la petición")

    } catch (error) {
        console.error("Error al cargar audios:", error)
        moment.value = false
    }
}

async function SetPlay(x) {
    if (durationSong.value >= 15) {
        try {
            const sesion = localStorage.getItem("token")
            if (!sesion) return
            const currentAudio = songs.value[currentIndex.value]

            const payload = {
                idReproduccion: idPlay.value,
                tiempo: durationSong.value,
                idUser: sesion,
                idAudio: currentAudio.id + '',
                home: false
            };

            if (isOffline.value) {
                const key = `offline_plays_${sesion}`;
                let queue = [];
                try {
                    queue = JSON.parse(localStorage.getItem(key) || '[]');
                } catch (e) { console.error(e); }
                queue.push(payload);
                localStorage.setItem(key, JSON.stringify(queue));
                if (x === 0) idPlay.value = 0;
                return;
            }

            const response = await fetch(`${API_BASE_URL}/api/config/SetPlay`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(payload),
                keepalive: true
            })
            const data = await response.json()
            if (!response.ok) throw new Error("Error en la petición")
            else {
                if (x == 0)
                    idPlay.value = 0
                else
                    idPlay.value = data.data
            }
        } catch (error) {
            console.error("Error al cargar audios:", error)
        }
    }
}
const MOMENT_SESSION_KEY = 'moment_popup_session'

function getHalfHourSessionKey() {
    const now = new Date()

    const year = now.getFullYear()
    const month = String(now.getMonth() + 1).padStart(2, '0')
    const day = String(now.getDate()).padStart(2, '0')
    const hour = String(now.getHours()).padStart(2, '0')

    const minutes = now.getMinutes()

    // 👇 tu lógica especial
    const block = minutes <= 30 ? '01-30' : '31-00'

    return `${year}-${month}-${day}-${hour}-${block}`
}

function hasShownMomentThisSession() {
    const currentSession = getHalfHourSessionKey()
    return localStorage.getItem(MOMENT_SESSION_KEY) === currentSession
}

function markMomentAsShown() {
    const currentSession = getHalfHourSessionKey()
    localStorage.setItem(MOMENT_SESSION_KEY, currentSession)
}

